import sys

class Solution:
    def maxChocolatesCollected(self, grid: list[list[int]]) -> int:
        R, C = len(grid), len(grid[0])
        memo = {}

        def dfs(r, c1, c2):
            if r == R:
                return 0
            if (r, c1, c2) in memo:
                return memo[(r, c1, c2)]
            res = grid[r][c1] + grid[r][c2] if c1 != c2 else grid[r][c1]
            max_chocolates = 0
            for dc1 in [-1, 0, 1]:
                for dc2 in [-1, 0, 1]:
                    n_c1, n_c2 = c1 + dc1, c2 + dc2
                    if 0 <= n_c1 < C and 0 <= n_c2 < C:
                        max_chocolates = max(max_chocolates, dfs(r + 1, n_c1, n_c2))
            memo[(r, c1, c2)] = res + max_chocolates
            return memo[(r, c1, c2)]

        return dfs(0, 0, C - 1)

