#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int maxChocolatesCollected(vector<vector<int>>& grid) {
        int R = grid.size(), C = grid[0].size();
        vector<vector<vector<int>>> memo(R, vector<vector<int>>(C, vector<int>(C, -1)));

        function<int(int, int, int)> dfs = [&](int r, int c1, int c2) {
            if (r == R) return 0;
            if (memo[r][c1][c2] != -1) return memo[r][c1][c2];
            int res = (c1 != c2) ? grid[r][c1] + grid[r][c2] : grid[r][c1];
            int max_chocolates = 0;
            for (int dc1 = -1; dc1 <= 1; dc1++) {
                for (int dc2 = -1; dc2 <= 1; dc2++) {
                    int n_c1 = c1 + dc1, n_c2 = c2 + dc2;
                    if (0 <= n_c1 && n_c1 < C && 0 <= n_c2 && n_c2 < C) {
                        max_chocolates = max(max_chocolates, dfs(r + 1, n_c1, n_c2));
                    }
                }
            }
            memo[r][c1][c2] = res + max_chocolates;
            return memo[r][c1][c2];
        };

        return dfs(0, 0, C - 1);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int R, C;
    if (!(cin >> R >> C)) return 0;
    vector<vector<int>> grid(R, vector<int>(C));
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (!(cin >> grid[i][j])) return 0;
        }
    }
    Solution sol;
    int ans = sol.maxChocolatesCollected(grid);
    cout << ans << '\n';
    return 0;
}
